package quicdissector

import (
	"encoding/hex"
	"testing"
)

func TestSniffQUIC_RealTraffic(t *testing.T) {
	tests := []struct {
		name    string
		pktHex  []string
		wantSNI string
	}{
		{
			name: "cloudflare-quic.com",
			pktHex: []string{
				"",
				"",
				"",
				"",
			},
			wantSNI: "cloudflare-quic.com",
		},
		{
			name: "example.com",
			pktHex: []string{
				"",
				"",
			},
			wantSNI: "example.com",
		},
		{
			name: "www.google.com",
			pktHex: []string{
				"",
				"",
				"",
				"",
				"",
				"",
				"",
				"",
				"",
				"",
			},
			wantSNI: "www.google.com",
		},
	}

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			var pkts [][]byte
			for i, h := range tc.pktHex {
				data, err := hex.DecodeString(h)
				if err != nil {
					t.Fatalf("pkt-%d: hex decode: %v", i, err)
				}
				t.Logf("pkt-%d: len=%d first=0x%02x", i, len(data), data[0])
				pkts = append(pkts, data)
			}
			info, err := SniffQUIC(pkts...)
			if err != nil {
				t.Fatalf("SniffQUIC: %v", err)
			}
			t.Logf("SNI=%q  ALPN=%v", info.ServerName, info.SupportedProtos)
			if info.ServerName != tc.wantSNI {
				t.Errorf("ServerName = %q, want %q", info.ServerName, tc.wantSNI)
			}
		})
	}
}
